	priority: 1,
	labels: ['ddx', 'ui']
};

async function mockLongIdGraphQL(
	page: import('@playwright/test').Page,
	overrideId?: string
) {
	const beadId = overrideId ?? LONG_ID;
	const row = { ...LONG_BEAD_ROW, id: beadId };
	const detail = { ...LONG_BEAD_DETAIL, id: beadId };
